/**
 * Admin · Seed kids-teaching — production CSV import UI.
 *
 * Hits POST /admin/seed/kids-teaching. Supports dry-run preview, displays a
 * summary plus a scrollable PIN table. Operators distribute PINs to families.
 */

import { useState } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { runKidsTeachingSeed, type SeedReport } from '../api/admin'

export default function AdminSeed() {
  const { toast, show } = useToast()
  const [report, setReport] = useState<SeedReport | null>(null)
  const [loading, setLoading] = useState(false)
  const [lastMode, setLastMode] = useState<'dry' | 'real' | null>(null)

  async function run(dryRun: boolean) {
    setLoading(true)
    try {
      const r = await runKidsTeachingSeed(dryRun)
      setReport(r)
      setLastMode(dryRun ? 'dry' : 'real')
      show(dryRun ? 'Dry-run завершён' : 'Импорт завершён', 'success')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setLoading(false)
    }
  }

  function downloadPinsCsv() {
    if (!report || report.students.pins.length === 0) return
    const header = 'login,name,pin\n'
    const body = report.students.pins
      .map((p) => `${csvEscape(p.login)},${csvEscape(p.name)},${csvEscape(p.pin)}`)
      .join('\n')
    const blob = new Blob([header + body], { type: 'text/csv;charset=utf-8' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `kids-teaching-pins-${new Date().toISOString().slice(0, 10)}.csv`
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    URL.revokeObjectURL(url)
  }

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div
          role="status"
          aria-live="polite"
          style={{
            position: 'fixed', top: 20, right: 20, zIndex: 9999,
            background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7',
            color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600,
            boxShadow: '0 4px 24px rgba(0,0,0,0.15)',
          }}
        >
          {toast.msg}
        </div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>📦</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Production · Seeding</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Импорт kids-teaching</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1100, margin: '24px auto', padding: '0 16px', display: 'flex', flexDirection: 'column', gap: 20 }}>

        {/* Action card */}
        <div className="kb-card" style={{ padding: 22, display: 'flex', flexDirection: 'column', gap: 14 }}>
          <h2 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>Действия</h2>
          <p style={{ margin: 0, fontSize: 13, color: 'var(--ink-soft)', lineHeight: 1.55 }}>
            Импорт читает <code>scripts/kids-teaching.csv</code> из контейнера и
            идемпотентно создаёт учителей / классы / учеников / родителей / подписки / слоты.
            Сначала всегда <strong>DRY-RUN</strong> — он откатывает транзакцию и просто показывает,
            что будет создано. PIN-коды генерируются случайно и видны только в этом отчёте.
          </p>

          <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
            <button
              className="kb-btn"
              onClick={() => void run(true)}
              disabled={loading}
              style={{ fontWeight: 700 }}
            >
              {loading && lastMode === 'dry' ? '⏳ Анализирую…' : '🔍 DRY-RUN'}
            </button>
            <button
              className="kb-btn"
              onClick={() => void run(false)}
              disabled={loading}
              style={{ background: '#dc2626', color: '#fff', borderColor: '#dc2626', fontWeight: 800 }}
            >
              {loading && lastMode === 'real' ? '⏳ Импортирую…' : '📦 ИМПОРТ В БД'}
            </button>
          </div>
        </div>

        {/* Report */}
        {report && (
          <>
            {/* Summary chips */}
            <div className="kb-card" style={{ padding: 22, display: 'flex', flexDirection: 'column', gap: 14 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 8 }}>
                <h2 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>Сводка</h2>
                <span
                  style={{
                    fontSize: 12, fontWeight: 800, padding: '3px 10px', borderRadius: 999,
                    background: report.dryRun ? '#fef3c7' : '#dcfce7',
                    color: report.dryRun ? '#92400e' : '#166534',
                  }}
                >
                  {report.dryRun ? 'DRY-RUN (rollback)' : 'COMMITTED'}
                </span>
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 10 }}>
                <Stat label="Учителя" created={report.teachers.created} existed={report.teachers.existed} />
                <Stat label="Классы" created={report.classrooms.created} existed={report.classrooms.existed} />
                <Stat label="Ученики" created={report.students.created} existed={report.students.existed} />
                <Stat label="Родители" created={report.parents.created} existed={report.parents.existed} />
                <Stat label="Подписки" created={report.subscriptions.created} existed={report.subscriptions.existed} />
                <Stat label="Слоты" created={report.slots.created} existed={report.slots.skipped} createdLabel="создано" existedLabel="пропущено" />
              </div>
            </div>

            {/* Teachers */}
            {report.teachers.list.length > 0 && (
              <div className="kb-card" style={{ padding: 22, display: 'flex', flexDirection: 'column', gap: 12 }}>
                <h3 style={{ margin: 0, fontSize: 16, fontWeight: 800 }}>
                  Учителя ({report.teachers.list.length} новых)
                </h3>
                <div style={{ overflowX: 'auto', maxHeight: 240 }}>
                  <table style={tableStyle}>
                    <thead>
                      <tr style={theadRowStyle}>
                        <th style={thStyle}>Логин</th>
                        <th style={thStyle}>ФИО</th>
                      </tr>
                    </thead>
                    <tbody>
                      {report.teachers.list.map((t, i) => (
                        <tr key={t.login} style={{ background: i % 2 === 0 ? '#fff' : 'var(--bg-soft, #f9f8ff)', borderBottom: '1px solid var(--border, #e5e2f0)' }}>
                          <td style={{ ...tdStyle, fontFamily: 'monospace', fontWeight: 700 }}>{t.login}</td>
                          <td style={tdStyle}>{t.name}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
                <p style={{ margin: 0, fontSize: 12, color: 'var(--ink-soft)' }}>
                  Дефолтный пароль: <code>Eduson2026!</code> — раздай учителям и попроси сменить.
                </p>
              </div>
            )}

            {/* PINs */}
            {report.students.pins.length > 0 && (
              <div className="kb-card" style={{ padding: 22, display: 'flex', flexDirection: 'column', gap: 12 }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 8 }}>
                  <h3 style={{ margin: 0, fontSize: 16, fontWeight: 800 }}>
                    PIN-коды учеников ({report.students.pins.length})
                  </h3>
                  <button className="kb-btn" onClick={downloadPinsCsv} style={{ fontSize: 13, padding: '6px 12px' }}>
                    ⬇ CSV
                  </button>
                </div>
                <p style={{ margin: 0, fontSize: 12, color: 'var(--ink-soft)' }}>
                  Видны один раз — сохрани CSV и распространи операторам безопасным каналом.
                </p>
                <div style={{ overflowX: 'auto', maxHeight: 480, border: '1px solid var(--border, #e5e2f0)', borderRadius: 10 }}>
                  <table style={tableStyle}>
                    <thead style={{ position: 'sticky', top: 0, zIndex: 1 }}>
                      <tr style={theadRowStyle}>
                        <th style={thStyle}>Логин</th>
                        <th style={thStyle}>ФИО ребёнка</th>
                        <th style={thStyle}>PIN</th>
                      </tr>
                    </thead>
                    <tbody>
                      {report.students.pins.map((p, i) => (
                        <tr key={p.login} style={{ background: i % 2 === 0 ? '#fff' : 'var(--bg-soft, #f9f8ff)', borderBottom: '1px solid var(--border, #e5e2f0)' }}>
                          <td style={{ ...tdStyle, fontFamily: 'monospace', fontWeight: 700 }}>{p.login}</td>
                          <td style={tdStyle}>{p.name}</td>
                          <td style={{ ...tdStyle, fontFamily: 'monospace', fontWeight: 800, color: 'var(--violet, #6b5ce7)' }}>
                            {p.pin}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {/* Skipped rows */}
            {report.skippedRows.length > 0 && (
              <div className="kb-card" style={{ padding: 22, display: 'flex', flexDirection: 'column', gap: 12 }}>
                <h3 style={{ margin: 0, fontSize: 16, fontWeight: 800, color: '#92400e' }}>
                  Пропущенные строки / слоты ({report.skippedRows.length})
                </h3>
                <div style={{ overflowX: 'auto', maxHeight: 320 }}>
                  <table style={tableStyle}>
                    <thead>
                      <tr style={theadRowStyle}>
                        <th style={thStyle}>Строка</th>
                        <th style={thStyle}>Причина</th>
                      </tr>
                    </thead>
                    <tbody>
                      {report.skippedRows.map((s, i) => (
                        <tr key={i} style={{ background: i % 2 === 0 ? '#fff' : 'var(--bg-soft, #fffbeb)', borderBottom: '1px solid var(--border, #e5e2f0)' }}>
                          <td style={{ ...tdStyle, fontFamily: 'monospace' }}>{s.row || '?'}</td>
                          <td style={tdStyle}>{s.reason}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </PlatformShell>
  )
}

// ─── helpers ──────────────────────────────────────────────────────────

function Stat(props: {
  label: string
  created: number
  existed: number
  createdLabel?: string
  existedLabel?: string
}) {
  return (
    <div
      style={{
        padding: 14, borderRadius: 12,
        border: '1.5px solid var(--border, #e5e2f0)',
        background: '#fff',
        display: 'flex', flexDirection: 'column', gap: 4,
      }}
    >
      <div style={{ fontSize: 12, color: 'var(--ink-soft)', fontWeight: 600 }}>{props.label}</div>
      <div style={{ display: 'flex', gap: 12, alignItems: 'baseline' }}>
        <div>
          <span style={{ fontSize: 22, fontWeight: 900, color: 'var(--violet, #6b5ce7)' }}>{props.created}</span>
          <span style={{ fontSize: 11, color: 'var(--ink-soft)', marginLeft: 4 }}>
            {props.createdLabel ?? 'создано'}
          </span>
        </div>
        <div>
          <span style={{ fontSize: 16, fontWeight: 700, color: 'var(--ink-soft)' }}>{props.existed}</span>
          <span style={{ fontSize: 11, color: 'var(--ink-soft)', marginLeft: 4 }}>
            {props.existedLabel ?? 'было'}
          </span>
        </div>
      </div>
    </div>
  )
}

function csvEscape(value: string): string {
  if (/[",\n]/.test(value)) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

const tableStyle: React.CSSProperties = {
  width: '100%', borderCollapse: 'collapse', fontSize: 14,
}

const theadRowStyle: React.CSSProperties = {
  background: 'var(--bg-soft, #f5f3ff)', textAlign: 'left',
}

const thStyle: React.CSSProperties = {
  padding: '10px 14px', fontWeight: 800, whiteSpace: 'nowrap', fontSize: 13,
}

const tdStyle: React.CSSProperties = {
  padding: '8px 14px', fontSize: 13,
}
