/**
 * Admin-only operational API calls — production seeding etc.
 *
 * Backed by NestJS endpoints under /api/v1/admin/seed/*. Guarded by
 * JwtAuthGuard + RolesGuard('admin', 'platform_admin') on the server side.
 */

import { api } from './client'

export interface SeedReport {
  teachers: {
    created: number
    existed: number
    list: { login: string; name: string }[]
  }
  classrooms: { created: number; existed: number }
  students: {
    created: number
    existed: number
    pins: { login: string; name: string; pin: string }[]
  }
  parents: { created: number; existed: number }
  subscriptions: { created: number; existed: number }
  slots: { created: number; skipped: number }
  skippedRows: { row: number; reason: string }[]
  dryRun: boolean
}

/**
 * POST /admin/seed/kids-teaching — imports the kids-teaching CSV.
 * Pass `dryRun: true` to parse + simulate without committing writes.
 */
export function runKidsTeachingSeed(dryRun = false): Promise<SeedReport> {
  return api.post<SeedReport>('/admin/seed/kids-teaching', { dryRun })
}
